{"version":3,"sourceRoot":"","sources":["../../scss/partials/_base.scss","../../scss/partials/_header.scss","../../scss/partials/_contactUs.scss","../../scss/partials/_footer.scss","../../scss/references.scss"],"names":[],"mappings":"AAeY;AACA;ACdZ;EACI;EACA;EACA;;AAEA;EACI,YDPQ;ECQR;EACA;EACA;EACA;EACA;EACA;EACA;;AAEA;EACI;;AAGJ;EACI;EACA;;AAEA;EACI;;AAIR;EACI;EACA;;AAIR;EAEI;EACA;EAEA;EACA;;AAGI;EACI;;AAEJ;EACI;;AAKZ;EACI;EACA;EACA;EACA;EACA;EACA;EACA;;AAGJ;EACI;EACA;EACA;EACA;EACA;EACA;EACA,kBD9DkB;EC+DlB;EACA;;AAEA;EACI;EACA;EACA;EACA;EACA;EACA;EACA;EACA;;AAGJ;EACI;EACA;;;AAKZ;EACI;EACA;EACA;EACA;;AAEA;EACI;;;AAIR;EACI;EACA;;;AAGJ;EACI;EACA;EACA;EACA;EACA;;;AAGJ;EACI;EACA;;;AAGJ;EACI;IACI;;EAEJ;IACI;;;AAIR;EACI;IACI;;EAEJ;IACI;;;AAOJ;EACI;EACA;AACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA,ODtJO;ECuJP;EACA;EACA;;AAEA;EACI;EACA;;AAGJ;EACI;EACA;;AAGJ;EACI,ODtKG;ECuKH;;AAKR;EACI;EACA;EACA;EACA;EACA;EACA;EACA;;AAEA;EACI;EACA;;AAIR;EACI;EACA;EACA;EACA;;AAGJ;EACI;EACA;;;AAMJ;EACI;EACA;EACA;EACA;EACA;EACA;;AAEA;EACI;EACA;;AAGJ;EACI,kBD/NI;ECgOJ;EACA;EACA;;AAEA;EACI;;AAGJ;EACI,kBDxOA;;AC4OR;EACI;EACA;EACA;EACA;EACA;;AAEA;EACI,ODrPA;;ACwPJ;EACI;;AAGJ;EACI;;;AAMhB;EACI;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;;AAGA;EACI;EACA;EACA;EACA;EACA;EACA;EACA;;AAGJ;EACI;EACA;EACA;EACA;EACA;EACA;EACA;;AAEA;EACI;EACA;EACA;EACA;;AAGJ;EACI;;AAGJ;EACI;EACA;;AAIR;EACI;EACA;EACA;EACA;EACA;;AAEA;EACI;EACA;;;AAKZ;EACI;IACI;;EAEJ;IACI;;;AAIR;EACI;;;AAGJ;EACI;EACA;EACA;EACA;EACA;;;AAGJ;EACI;;;AAGJ;EACI;;;AAGJ;EAEI;IACI;IACA;IACA;IACA;IACA;;EAEA;IACI;;EAKJ;IACI;IACA;;EAEA;IACI;;EAEJ;IACI;;EAKZ;IACI;IACA;IACA;IACA;IACA;;EAGJ;AACI;AAAA;AAAA;AAAA;AAAA;AAAA;IAMA;;EAGJ;IACI;IACA;IACA;;EAGJ;IACI;IACA;IACA;IACA;;EAGJ;IACI;;;AAKR;EAEI;IACI;IACA;;EAGJ;IACI;IACA;;EAGJ;IACI;;EAGJ;IACI;;EAGJ;IACI;IACA;IACA;;;AAKR;EACI;;;AAGJ;EACI;EACA;EACA;;;AAGJ;EACI;EACA;EACA;;AAEA;EACI;;;AAKJ;EACI;;;AAKJ;EACI;;;AAIR;EACI;EACA;EACA;EACA;;AAEA;EACI;EACA;;;ACjeR;EACI;EACA;EAEA;EACA;EACA;EACA;;;AAIJ;EACI;EACA;EACA;EACA;EACA;EACA;EACA;;;AAGJ;EACI;EACA;;;AAIJ;EACI;EAGA;EACA;EAEA;EACA;;AFIA;EACI,OA3CQ;EA4CR;EACA;EACA;;AAGJ;EACI,OA3CO;EA4CP;EACA;EACA;EACA;EACA;EACA;;AAGJ;EACI,OA5DQ;EA6DR;EACA;EACA;EACA;EACA;;AAGJ;EACI,OA9DO;EA+DP;EACA;EACA;EACA;EACA;;AAGJ;EACI;;AEtCJ;EACI;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;EACA;;AACA;EACI;EACA;EACA;;AAMR;EACI;EACA;EACA;EACA;EACA;;AAEA;EACI;;AAEA;EACI;;AAGR;EACI,OF5EI;;AE+EA;EACI;;AAEJ;EACI;;AAMhB;EACI;;;AAIR;EAEQ;IACI;IACA;IACA;IACA;IACA;IACA;IACA;IACA;;EAGJ;IACI;IACA;IACA;;EACA;IACI;IACA;IACA;;EAKZ;IACI;IACA;IACA;IACA;;EAGJ;IACI;IACA;;;AAKR;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;AAAA;;AAAA;AAAA;;AAAA;AAAA;AAAA;AAAA;AAAA;ACzBA;EAEQ;IACI;IACA;;EAGJ;IACI;IACA;;;AHpGR;EACI;EACA;EACA;EACA;EACA,yBACI;;;AAGR;EACI;EACA;EACA;;;AAGJ;EACI,aAtBG;EAuBH,OA3BO;EA4BP;EACA;EACA;;;AI/BR;EACI;EACA;EACA;EACA;EAEA;EACA;EACA;;;ADZA;EAaI,kBHPkB;EGQlB;EACA;;AAZA;EACI;EACA;EACA;EACA;EACA;EACA;EACA;;AAOJ;EACI;EACA;EACA;EACA;EACA;EACA;EACA;EACA;;AAGJ;EACI;;AACA;EACI;EACA;EACA;EACA;;AAEA;EACI;;AAGJ;EACI;;AAGJ;EACI;;AAIR;EACI;EACA;;AAIR;EACI;EACA;EACA;EACA;;AACA;EACI,OHxDD;EGyDC;EACA;EACA;;AAKR;EACI;EACA;EACA;;AAGJ;EACI;EACA;EACA;EACA;EACA,OH3EG;EG4EH;EACA;EACA;EACA;EACA;EACA;;AAEA;EACI;EACA;;AAIR;EACI;EACA;EACA;;AAEA;EACI","sourcesContent":["// Colors\n$windchillBlue: #0062B8;\n$raspberryBlue: #2DABE3;\n$windchillPurple: #97005E;\n$windchillYellow: #ffa200;\n$windchillYellowLight: #F4B860;\n\n    // Different greys used\n    $mainDark: #5b5b5b;\n    $backgroundLightGrey: #ececec;\n\n// Fonts\n$mainFont: \"Sansation\", sans-serif;\n\n@mixin universalStyle {\n    @import \"https://www.nerdfonts.com/assets/css/webfont.css\";\n    @import url('https://fonts.googleapis.com/css2?family=Roboto:ital,wght@0,432;1,432&family=Sansation:ital,wght@0,300;0,400;0,700;1,300;1,400;1,700&display=swap');\n\n    .roboto-tmp {\n        font-family: \"Roboto\", sans-serif;\n        font-optical-sizing: auto;\n        font-weight: 432;\n        font-style: normal;\n        font-variation-settings:\n            \"wdth\" 100;\n    }\n\n    .sansation-light {\n        font-family: \"Sansation\", sans-serif;\n        font-weight: 300;\n        font-style: normal;\n    }\n\n    body, html {\n        font-family: $mainFont;\n        color: $mainDark;\n        margin: 0px;\n        padding: 0px;\n        font-size: 100%;\n    }\n}\n\n@mixin textStyle($h3-color: $mainDark, $h2-color: $windchillBlue, $p-color: $mainDark, $h4-color: $windchillBlue) {\n    h4 {\n        color: $h4-color;\n        font-size: 1.2rem;\n        font-weight: 400;\n        text-transform: uppercase;\n    }\n\n    h3 {\n        color: $h3-color;\n        text-transform: uppercase;\n        margin-block-start: 0;\n        margin-block-end: 0;\n        font-size: 1.17rem;\n        margin-bottom: .2rem;\n        font-weight: 200;\n    }\n\n    h2 {\n        color: $h2-color;\n        text-transform: uppercase;\n        font-size: 2rem;\n        margin-block-start: 0;\n        margin-block-end: 0;\n        font-weight: 200;\n    }\n\n    p {\n        color: $p-color;\n        line-height: 1.5;\n        font-size: 1.1rem;\n        font-weight: 200;\n        margin-block-start: 1rem;\n        margin-block-end: 1rem;\n    }\n\n    h1 {\n        font-weight: 400;\n    }\n}\n\n@mixin sectionDefs {\n    padding-top: 75px;\n    padding-bottom: 75px;\n    padding-left: 10%;\n    padding-right: 10%;\n}\n\n@mixin paragraphSpans($primary: $mainDark, $secondary: $windchillBlue) {\n    @include textStyle($h3-color: $primary, $h2-color: $secondary, $p-color: $primary, $h4-color: $secondary);\n\n    h3 {\n        font-weight: 400;\n    }\n\n    h2 {\n        font-weight: 400;\n    }\n\n    p {\n        font-weight: 400;\n        line-height: 1.7;\n    }\n\n    .single_span, .double_span {\n        margin-left: 10%;\n        width: 80%;\n    }\n\n    .double_span {\n        display: flex;\n        flex-direction: row;\n        flex-wrap: wrap;\n        flex-grow: 1;\n        flex-shrink: 1;\n        &  > span {\n            min-width: 25ch;\n        }\n        gap: 2rem;\n\n        & > span:first-child {\n            flex: 45;\n        }\n\n        & > span:last-child {\n            flex: 55;\n        }\n    }\n\n    .double_span:has(ul) {\n        & > span {\n            flex: 55 !important;\n        }\n\n        & > span:has(ul) {\n            flex: 45 !important;\n        }\n    }\n\n    ul {\n        list-style: none;\n        font-size: 1.3rem;\n        padding: 0;\n        margin: 0;\n\n        li {\n            display: flex;\n            align-items: flex-start;\n            gap: .5rem;\n            margin-top: .5rem;\n            margin-bottom: .5rem;\n            line-height: 1.5;\n        }\n\n        .nf {\n            display: inline-flex;\n            vertical-align: middle;\n            color: $primary;\n            font-size: .7rem;\n            padding: .3rem;\n            border: 1px solid $secondary;\n            border-radius: 50%;\n            margin-right: .5rem;\n            margin-top: .3rem;\n        }\n\n    }\n}\n\n@mixin cardsFlex($h3-color, $border-color: $raspberryBlue) {\n\n    $marginCard: 1.2rem;\n\n    @include textStyle($h3-color: $h3-color);\n\n    display: flex;\n    justify-content: space-between;\n    row-gap: 40px;\n    width: 80%;\n    margin-left: 10%;\n    flex-wrap: wrap;\n    margin-top: 50px;\n\n    a.card {\n        text-decoration: none;\n    }\n\n    .card {\n        width: 350px;\n        min-height: 450px;\n        height: auto;\n        border: 2px solid $border-color;\n        background-color: white;\n        cursor: pointer;\n        transform: scale(1);\n        transition: transform 0.3s ease;\n        display: grid;\n        grid-template-rows: 248px 2.5rem 1fr 1rem;\n        padding-bottom: $marginCard;\n\n        &:hover {\n            transform: scale(1.03);\n        }\n\n        .image_crop_box {\n            width: 100%;\n            height: 248px;\n            overflow: hidden;\n            position: relative;\n            background-color: white;\n            object-fit: cover;\n            border-bottom: 2px solid $border-color;\n\n            img {\n                width: 100%;\n                height: 248px;\n                object-fit: cover;\n                object-position: center;\n                display: block;\n            }\n        }\n\n        h3 {\n            text-transform: uppercase;\n            padding-left: $marginCard;\n            padding-top: $marginCard;\n            color: $h3-color;\n            font-weight: 400;\n            flex-grow: 1;\n        }\n        \n        p {\n            flex-grow: 1;\n            padding: $marginCard;\n        }\n\n        .learn_more {\n            color: $h3-color;\n            text-align: right;\n            padding-right: $marginCard;\n        }\n    }\n\n    @media (max-width: 1350px) {\n        justify-content: space-evenly !important;\n    }\n}\n\n@mixin centerFlex($x: true, $y: true) {\n    .center_flex {\n        display: flex;\n\n        @if $x {\n            width: 100%;\n            justify-content: center;\n        }\n\n        @if $y {\n            height: 100%;\n            align-items: center;\n        }\n\n    }\n}","@use \"base\";\n\nheader {\n    position: sticky;\n    top: 0;\n    z-index: 100;\n\n    #top_header {\n        background: base.$windchillBlue;\n        background: linear-gradient(332deg, base.$windchillBlue 0%, base.$raspberryBlue 100%);\n        color: white;\n        padding-top: .4rem;\n        padding-bottom: .4rem;\n        padding-left: 23px;\n        z-index: 150;\n        font-size: .85rem;\n\n        .nf {\n            margin-right: 5px;\n        }\n\n        a {\n            color: white;\n            text-decoration: none;\n\n            &:hover {\n                text-decoration: under;\n            }\n        }\n\n        #splitter {\n            margin-right: .75rem;\n            margin-left: .75rem;\n        }\n    }\n\n    #site_header {\n        //display: flex;\n        position: absolute;\n        width: 100%;\n        //flex-direction: column;\n        border-bottom: 1px solid lightgrey;\n        background-color: white;\n\n        .nf {\n            &.nf-fa-navicon {\n                display: none;\n            }\n            &.nf-fa-angle_down {\n                font-size: .8rem;\n            }\n        }\n    }\n\n    #main_block {\n        display: flex;\n        align-items: center;\n        justify-content: space-between;\n        height: max-content;\n        padding-left: 30px;\n        padding-top: 15px;\n        padding-bottom: 15px;\n    }\n\n    #nav_tabs {\n        display: flex;\n        font-size: .8rem;\n        border-top: 1px solid lightgrey;\n        color: #525252;\n        align-items: center;\n        position: relative;\n        background-color: base.$backgroundLightGrey;\n        height: 3em;\n        font-weight: 400;\n\n        & > div {\n            display: flex;\n            gap: .4rem;\n            align-items: center;\n            justify-content: space-between;\n            height: 100%;\n            padding-left: 2rem;\n            padding-right: 2rem;\n            position: relative;\n        }\n\n        & > div:hover:not(:has(.dropdown_content:hover)) {\n            background-color: #d1d1d1;\n            cursor: pointer;\n        }\n    }\n}\n\n#img_home_link {\n    height: 100%;\n    display: flex;\n    justify-content: center;\n    align-items: center;\n\n    &:hover {\n        background-color: lightgray;\n    }\n}\n\n#logo_and_name {\n    display: flex;\n    align-items: center;\n}\n\n#webpage_title {\n    font-size: 1.5rem;\n    font-weight: 800;\n    margin-left: 40px;\n    padding-left: 40px;\n    border-left: 3px solid lightgray; \n}\n\n#windchill_logo {\n    height: 80px;\n    cursor: pointer;\n}\n\n@keyframes expand {\n    from {\n        max-height: 0px;\n    }\n    to {\n        max-height: 700px; /* Adjust this based on your content */\n    }\n}\n\n@keyframes shrink {\n    from {\n        max-height: 700px;\n    }\n    to {\n        height: 0px; /* Adjust this based on your content */\n    }\n}\n\n#main_header {\n\n\n    #nav_tabs .dropdown_content {\n        display: none;\n        font-family: \"Sansation\", sans-serif;\n        /*display: none;*/\n        position: absolute;\n        top: 100%;\n        left: 0;\n        flex-direction: column;\n        width: max-content;\n        min-width: 300px;\n        background-color: white;\n        z-index: 2;\n        margin-top: 10px;\n        box-shadow: rgba(50, 50, 93, 0.25) 0px 6px 12px -2px, rgba(0, 0, 0, 0.3) 0px 3px 7px -3px;\n        outline: 1px solid lightgrey;\n        color: base.$mainDark;\n        flex-shrink: 0;\n        flex-grow: 0;\n        overflow: hidden;\n\n        &.hide_dropdown {\n            animation: shrink 1s forwards;\n            display: flex !important;\n        }\n\n        &.show_dropdown {\n            animation: expand 1s forwards;\n            display: flex !important;\n        }\n    \n        a {\n            color: base.$mainDark;\n            text-decoration: none;\n        }\n    \n    }\n\n    .option {\n        padding-left: 20px;\n        padding-right: 20px;\n        height: 3rem;\n        font-size: 1rem;\n        display: flex;\n        align-items: center;\n        cursor: pointer;\n\n        &:hover {\n            background-color: #ebebeb;\n            color: black;\n        }\n    }\n    \n    .tab_clicked {\n        background-color: #d1d1d1;\n        outline: 2px dotted base.$windchillPurple;\n        z-index: 10;\n        color: black;\n    }\n    \n    #nav_tabs .nf {\n        font-size: 15px;\n        padding-top: 4px;\n    }\n    \n}\n\n#nav_icons, .mobile_buttons {\n    a {\n        padding: .75rem;\n        border-radius: 1.5rem;\n        cursor: pointer;\n        font-size: .9rem;\n        padding-left: 1.3rem;\n        padding-right: 1.3rem;\n        \n        .nf {\n            margin-right: .5rem;\n            font-size: 1.2rem;\n        }\n\n        &:first-child {\n            background-color: base.$windchillBlue;\n            color: white !important;\n            transition-property: background-color;\n            transition-duration: .2s;\n    \n            .nf {\n                color: white;\n            }\n\n            &:hover {\n                background-color: base.$raspberryBlue;\n            }           \n        }\n\n        &:last-child {\n            background-color: white;\n            color: base.$windchillBlue !important;\n            outline: 2px solid #0062B8;\n            transition-property: color, outline-color;\n            transition-duration: .2s;\n    \n            .nf {\n                color: base.$windchillBlue;\n            }\n\n            &:hover, &:hover .nf {\n                color: #00aeff;\n            }\n\n            &:hover {\n                outline-color: #00aeff;\n            }\n        }\n    }\n}\n\n.mobile_nav {\n    display: flex;\n    position: absolute;\n    z-index: 100;\n    background-color: white;\n    align-items: center;\n    flex-direction: column;\n    justify-content: start;\n    align-items: start;\n    font-size: 1rem;\n    width: 100%;\n    \n\n    .dropdown_content {\n        display: flex;\n        flex-direction: column;\n        overflow: hidden;\n        grid-column: 1 / -1;\n        max-height: 0px;\n        transition: max-height 300ms, opacity 200ms ease;\n        will-change: max-height, opacity;\n    }\n\n    & > div:not(.mobile_buttons) {\n        display: grid;\n        grid-template-columns: 1fr 1fr;\n        grid-template-rows: 3rem auto;\n        border-top: 2px solid lightgrey;\n        margin-left: 5%;\n        width: 90%;\n        cursor: pointer;\n\n        span, i.nf {\n            width: 100%;\n            height: 100%;\n            display: flex;\n            align-items: center;\n        }\n\n        i.nf {\n            justify-content: end;\n        }\n        \n        a {\n            text-decoration: none;\n            color: #5B5B5B;\n        }\n    }\n\n    .mobile_buttons {\n        margin-top: 5%;\n        margin-bottom: 5%;\n        display: flex;\n        justify-content: space-around;\n        width: 100%;\n\n        a {\n            display: inline-block;\n            scale: 1;\n        }\n    }\n}\n\n@keyframes rotating {\n    from {\n        transform: rotateX(0deg);\n    }\n    to {\n        transform: rotateX(180deg);\n    }\n}\n\n.tab_clicked .nf {\n    animation: rotating .5s forwards;\n}\n\n#nav_icons {\n    display: flex;\n    align-items: center;\n    gap: 30px;\n    padding-right: 60px;\n    justify-content: end;\n}\n\n#nav_icons .nf {\n    color: #525252;\n}\n\n#header_margin {\n    margin-bottom: 150px;\n}\n\n@media (max-width: 750px) {\n\n    #nav_icon {\n        display: block !important;\n        position: absolute;\n        right: 0;\n        font-size: 30px;\n        margin-right: 30px;\n\n        &:hover {\n            background-color: #ebebeb;\n        }\n    }\n\n    header {\n        #nav_tabs {\n            display: none;\n            position: initial;\n\n            .show_dropdown {\n                position: relative;\n            }\n            .option {\n                font-size: 2.5rem;\n            }\n        }        \n    }\n\n    #main_block {\n        align-items: center;\n        justify-content: left !important;\n        padding-left: 0px !important;\n        margin-left: 30px;\n        row-gap: 20px;\n    }\n\n    #nav_icons {\n        /*\n        order: 2;\n        padding-right: 0px;\n        width: 100%;\n        justify-content: space-around;\n        */\n        display: none;\n    }\n\n    #logo_and_name {\n        order: 1;\n        justify-content: center;\n        padding-bottom: 0px;\n    }\n\n    #webpage_title {\n        margin-left: 1.2rem;\n        padding-left: 1.2rem;\n        font-size: 1.3rem;\n        max-width: 100px;\n    }\n\n    #windchill_logo {\n        height: 60px;\n    }\n\n}\n\n@media (max-width: 400px) {\n\n    .mobile_nav .mobile_buttons a {\n        display: inline-block;\n        scale: .8;\n    }\n\n    #nav_icon {\n        font-size: 25px;\n        margin-right: 25px;\n    }\n\n    #main_block {\n        margin-left: 25px;\n    }\n\n    #windchill_logo {\n        height: 40px;\n    }\n\n    #webpage_title {\n        font-size: 1rem;\n        margin-left: .8rem;\n        padding-left: .8rem;\n    }\n}\n\n// JQuery Classes\n.hide_me {\n    display: none !important;\n}\n\n.no_overflow {\n    width: 100%;\n    height: 100%;\n    overflow: hidden;\n}\n\n.slide_in {\n    transform: translateX(100%);\n    transition: transform 400ms cubic-bezier(.2,.9,.2,1), opacity 300ms ease;\n    will-change: transform, opacity;\n\n    &.is_visible {\n        transform: translateX(0);\n    }\n}\n\n.open_mobile_nav {\n    .dropdown_content {\n        max-height: 600px;\n    }\n}\n\n.hover_mobile_category {\n    span, i.nf {\n        background-color: lightgrey !important;\n    }\n}\n\n.init_header {\n    overflow: hidden;\n    max-height: 0px;\n    transition: max-height 700ms cubic-bezier(.2,.9,.2,1), opacity 300ms ease;\n    will-change: max-height, opacity;\n\n    &.is_visible {\n        max-height: 200px;\n        overflow: visible;\n    }\n}","@use \"base\";\n\n// @include base.centerFlex($x: false);\n\n.center_flex {\n    display: flex;\n    align-items: center;\n    //justify-content: center;\n    height: 100%;\n    margin-left: 10%;\n    flex-wrap: nowrap;\n    gap: 2.5rem;\n}\n\n\n#contact_about_card {\n    background-color: white;\n    padding-left: 2.5rem;\n    padding-right: 2.5rem;\n    max-width: 45ch;\n    flex-direction: column;\n    justify-content: center;\n    border-left: 2px solid base.$backgroundLightGrey;\n}\n\n#contact_icons {\n    display: flex;\n    justify-content: space-around;\n}\n\n\n#contact_us_section {\n    border-top: 8px solid base.$windchillBlue;\n    @include base.textStyle;\n\n    position: relative;\n    z-index: 1;\n    \n    object-fit: cover;\n    height: 600px;\n    \n    .image_crop_background {\n        z-index: 8;\n        position: absolute;\n        right: 0;\n        overflow: hidden;\n        object-fit: cover;\n        display: flex;\n        align-items: center;\n        z-index: -1;\n        height: 600px;\n        object-fit: cover;\n        width: 30%;\n        img {\n            height: 100%;\n            width: auto;\n            clip-path: polygon(15% 0, 100% 0, 100% 100%, 15% 100%, 0% 50%);\n            //clip-path: polygon(35% 0, 100% 0, 100% 100%, 0% 100%);\n        }\n    }\n\n    \n    .contact_option {\n        width: min-content;\n        cursor: pointer;\n        display: flex;\n        flex-direction: column;\n        align-items: center;\n        \n        img {\n            height: 4rem;\n            \n            &.contact_hover {\n                display: none;\n            }\n        }\n        &:hover {\n            color: base.$windchillBlue;\n            \n            img {\n                &.contact_hover {\n                    display: inline;\n                }\n                &.contact {\n                    display: none;\n                }\n            }\n        }\n    }\n    \n    h2, p {\n        text-align: center;\n    }\n}\n\n@media (max-width: 1300px) {\n    #contact_us_section {\n        .center_flex {\n            flex-direction: column;\n            backdrop-filter: blur(10px);\n            justify-content: center;\n            background-color: rgba(255, 255, 255, 0.651);\n            margin-left: 0px;\n            width: fit-content;\n            max-width: 85%;\n            margin: 0 auto;\n        }\n\n        .image_crop_background {\n            width: 100%;\n            display: flex;\n            align-items: center;\n            img {\n                height: auto;\n                width: 1300px;\n                clip-path: none;\n            }\n        }\n    }\n\n    #small_card {\n        text-align: center;\n        padding-top: 2.5rem;\n        padding-bottom: 2.5rem;\n        max-width: 80%;\n    }\n\n    #contact_about_card {\n        border-left: none;\n        background-color: transparent;\n    }\n    \n}\n\n/*\n#false_border {\n    position: absolute;\n    left: 0;\n    background-color: base.$windchillBlue;\n    height: 600px;\n    z-index: -2;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n\n    div {\n        background-color: white;\n\n        // This is actually the margin. Adjusting this will change the whole margin;\n        // margin-left: 8px; \n    }\n}\n*/","@use \"base\";\n\n@mixin footerStyle($background-color: base.$backgroundLightGrey) { // #e7e7e7 <--- old color\n    footer {\n\n        //Enforce default values in footer\n        h3 {\n            display: block;\n            font-size: .9rem;\n            margin-top: 0.67em;\n            margin-bottom: 0.67em;\n            margin-left: 0;\n            margin-right: 0;\n            font-weight: bold;\n        }\n\n        background-color: $background-color;\n        padding-top: 70px;\n        font-size: .9rem;\n\n        #footer_content_flex {\n            display: flex;\n            flex-wrap: wrap;\n            justify-content: space-between;\n            gap: 4rem;\n            width: 80%;\n            margin-left: 10%;\n            flex-shrink: 0;\n            flex-grow: 1;\n        }\n        \n        #footer_logo_flex {\n            width: min-content;\n            & > div {\n                display: flex;\n                justify-content: space-around;\n                align-items: center;\n                margin-top: .5rem;\n\n                & > div {\n                    font-weight: 600;\n                }\n\n                .nf:last-child {\n                    margin-left: .5ch;\n                }\n\n                .nf {\n                    font-size: 1.2rem;\n                }\n            }\n            \n            img#footer_logo {\n                height: 100px;\n                margin-bottom: 1em;\n            }\n        }\n\n        #web_map_links {\n            min-height: 160px;\n            display: grid;\n            column-gap: 1rem;\n            grid-template-columns: 1fr 1fr;\n            a {\n                color: base.$mainDark;\n                font-weight: 400;\n                text-decoration: underline;\n                cursor: pointer;\n                \n            }\n        }\n\n        #info_address {\n            display: flex;\n            flex-direction: column;\n            gap: .5em;\n        }\n\n        #web_dev_info {\n            margin-top: 80px;\n            padding-top: .5rem;\n            padding-bottom: .5rem;\n            border-top: 2px solid rgb(202, 202, 202);\n            color: base.$mainDark;\n            display: flex;\n            justify-content: center;\n            gap: 1ch;\n            grid-row-start: 2;\n            grid-column-start: 1;\n            grid-column-end: -1;\n\n            & > span > span {\n                text-decoration: underline;\n                font-weight: 600;\n            }\n        }\n\n        #website_creds {\n            display: flex;\n            flex-direction: column;\n            gap: .5rem;\n\n            img {\n                height: 1em;\n            }\n        }\n    }\n}\n\n@media (max-width: 500px) {\n    footer {\n        #web_map_links {\n            grid-template-columns: 1fr !important;\n            row-gap: 1rem;\n        }\n\n        #web_dev_info {\n            flex-direction: column;\n            align-items: center;\n        }\n    }\n}","@use \"partials/base\";\n@use \"partials/header\";\n@use \"partials/contactUs\";\n@use \"partials/footer\";\n\n@include base.universalStyle;\n\n#references {\n    margin-left: 10%;\n    width: 80%;\n    padding-top: 75px;\n    margin-bottom: 75px;\n\n    display: flex;\n    flex-direction: column;\n    gap:1em;\n}\n\n\n@include footer.footerStyle;"]}: 